SELECT m.*,
        v.vehicle_number,
       oa.enterprise_name
FROM t_maintenance m
LEFT JOIN t_vehicle v on v.vehicle_id = m.vehicle_id
LEFT JOIN t_oa_enterprise oa ON m.enterprise_id = oa.enterprise_id
WHERE m.deleted_flag = #{queryForm.deletedFlag}

    AND m.enterprise_id = #{queryForm.enterpriseId}


    AND m.vehicle_id = #{queryForm.vehicleId}


    AND m.vehicle_id IN

        #{item}



    AND DATE_FORMAT(m.maintenance_date,'%Y-%m-%d') >= #{queryForm.startDate}


    AND DATE_FORMAT(m.maintenance_date,'%Y-%m-%d') <= #{queryForm.endDate}


    ORDER BY m.create_time DESC

SELECT MAX(maintenance_id) FROM t_maintenance WHERE deleted_flag = #{deletedFlag} AND vehicle_id IN
#{id}
